module top_module(
    input  VPWR,
    input  UDP_IN,
    input  CLK,
    output UDP_OUT
);reg nwpwr;

    always @(posedge CLK) begin
        if (UDP_IN) begin
            nwpwr <= 0;
        end else begin
            nwpwr <= VPWR;
        end
    end

    assign UDP_OUT = nwpwr;

endmodule
